function cookiesToHeader(cookiesObj) {
    if (!cookiesObj || typeof cookiesObj !== "object") return "";
    const parts = [];

    for (const [name, c] of Object.entries(cookiesObj)) {
        if (!c) continue;
        // Node-RED cookie objects commonly use .value
        if (typeof c.value !== "undefined") {
            parts.push(`${name}=${c.value}`);
        }
    }
    return parts.join("; ");
}

